// @kern-source: agon-orchestration:25
export function workflowToolMetadata(toolName: string): Record<string,unknown>|undefined {
  return ORCHESTRATION_TOOLS.find((tool) => tool.name === toolName)?.annotations;
}

// @kern-source: agon-orchestration:30
export function listMcpTools(): Array<{name:string,description:string,inputSchema:Record<string,unknown>,annotations?:Record<string,unknown>}> {
  return [...ORCHESTRATION_TOOLS, ...ROOM_TOOLS, ...PROJECT_CONTEXT_TOOLS].map(t => {
    const annotations = workflowToolMetadata(t.name);
    return {
      name: t.name,
      description: t.description,
      inputSchema: t.inputSchema,
      ...(annotations !== undefined ? { annotations } : {}),
    };
  });
}

